   113→  /** Class representing a binding in CBName evaluation. The inherited value field is ignored. */
   114→  static class NameBinding extends Binding {
   115→    protected Suspension susp;
   116→    NameBinding(Variable v, Suspension s) { 
   117→      super(v,null);
   118→      susp = s;
   119→    }
   120→    public JamVal value() { return (susp == null) ? illegalForwardReference(var()) : susp.eval(); }
   121→    public void setBinding(Suspension s) { susp = s; }
   122→    public String toString() { return "[" + var + ", " + susp + "]"; }
   123→  }
