   209→/** A generalized lookup visitor class that returns the element matching the embedded var in a 
   210→  * PureList<Elemtype extends WithVariable>. If no match found, returns null. */
   211→class LookupVisitor<ElemType extends WithVariable> implements PureListVisitor<ElemType, ElemType> {
   212→  /** Variable to look up. */
   213→  Variable var;
   214→  
   215→  // Invariant: the lexer guarantees that there is only one Variable instance for a given name enabling == testing
   216→  
   217→  LookupVisitor(Variable v) { var = v; }
   218→  
   219→  /** Case for empty lists. */
   220→  public ElemType forEmpty(Empty<ElemType> e) { return null; }
   221→  
   222→  /** Case for non-empty lists. */
   223→  public ElemType forCons(Cons<ElemType> c) {
   224→    ElemType e = c.first();
   225→    if (var == e.var()) return e;
   226→    return c.rest().accept(this);
