/** A visitor class for the syntax checker. Returns normally unless there is a syntax error. On a syntax error,
  * throws a SyntaxException.
  */
class CheckVisitor implements ASTVisitor<Void> {

  /** Empty symbol table. */
  private static final Empty<Variable> EMPTY_VARS = new Empty<Variable>();

  /** Symbol table to detect free variables. */
  PureList<Variable> env;

  /** Root form of CheckVisitor. */
  public static final CheckVisitor INITIAL = new CheckVisitor(EMPTY_VARS);

  CheckVisitor(PureList<Variable> e) { env = e; }

  /** Factory method to create a new CheckVisitor with the given environment. */
  private CheckVisitor newCheckVisitor(PureList<Variable> newEnv) {
    return new CheckVisitor(newEnv);
  }

  /* ASTVisitor methods. */
  public Void forBoolConstant(BoolConstant b) { return null; }
  public Void forIntConstant(IntConstant i) { return null; }
  public Void forEmptyConstant(EmptyConstant n) { return null; }

  public Void forVariable(Variable v) {
    // Check if variable is in environment
    if (!env.contains(v)) {
      throw new SyntaxException("Free variable: " + v);
    }
    return null;
  }

  public Void forPrimFun(PrimFun f) { return null; }

  public Void forUnOpApp(UnOpApp u) {
    u.arg().accept(this);
    return null;
  }

  public Void forBinOpApp(BinOpApp b) {
    b.arg1().accept(this);
    b.arg2().accept(this);
    return null;
  }

  public Void forApp(App a) {
    a.rator().accept(this);
    for (AST arg : a.args()) {
      arg.accept(this);
    }
    return null;
  }

  public Void forMap(Map m) {
    // Check for duplicate parameter names
    Variable[] vars = m.vars();
    PureList<Variable> paramList = EMPTY_VARS;
    for (Variable v : vars) {
      if (paramList.contains(v)) {
        throw new SyntaxException("Duplicate parameter name: " + v);
      }
      paramList = paramList.cons(v);
    }

    // Check body with extended environment
    PureList<Variable> newEnv = env;
    for (Variable v : vars) {
      newEnv = newEnv.cons(v);
    }
    m.body().accept(newCheckVisitor(newEnv));
    return null;
  }

  public Void forIf(If i) {
    i.test().accept(this);
    i.conseq().accept(this);
    i.alt().accept(this);
    return null;
  }

  public Void forLet(Let l) {
    // Check for duplicate variable names in let bindings
    Variable[] vars = l.vars();
    PureList<Variable> letVars = EMPTY_VARS;
    for (Variable v : vars) {
      if (letVars.contains(v)) {
        throw new SyntaxException("Duplicate variable name in let: " + v);
      }
      letVars = letVars.cons(v);
    }

    // First check all right-hand sides in current environment
    AST[] exps = l.exps();
    for (AST exp : exps) {
      exp.accept(this);
    }

    // Then check body in extended environment (allows recursive let)
    PureList<Variable> newEnv = env;
    for (Variable v : vars) {
      newEnv = newEnv.cons(v);
    }
    l.body().accept(newCheckVisitor(newEnv));
    return null;
  }
}

/** Singleton visitor that checks for duplicate variables in a symbol table. Returns normally unless an error is found.
  * Throws a SyntaxException on error.
  */
class AnyDuplicatesVisitor implements PureListVisitor<Variable, Void> {
  public Void forEmpty(Empty<Variable> e) { return null; }

  public Void forCons(Cons<Variable> c) {
    Variable first = c.first();
    PureList<Variable> rest = c.rest();

    // Check if first appears in rest
    if (rest.contains(first)) {
      throw new SyntaxException("Duplicate variable: " + first);
    }

    // Check rest for duplicates
    rest.accept(this);
    return null;
  }
}

