/* Recursive let semantics: all let constructs support recursive bindings */
public JamVal forLet(Let l) {

  /* Extract binding vars and exps (rhs's) from l */
  Variable[] vars = l.vars();
  AST[] exps = l.exps();
  int n = vars.length;

  /* Create dummy bindings to support recursive references */
  Binding[] bindings = new Binding[n];
  PureList<Binding> newEnv = env();
  for(int i = 0; i < n; i++) {
    bindings[i] = bindingPolicy.newDummyBinding(vars[i]);
    newEnv = newEnv.cons(bindings[i]);
  }

  /* Create new EvalVisitor with extended environment */
  EvalVisitor newEV = newEvalVisitor(newEnv);

  /* Evaluate each RHS and update the corresponding binding */
  for(int i = 0; i < n; i++) {
    Suspension s = new ConcreteSuspension(exps[i], newEV);
    bindings[i].setBinding(s);
  }

  /* Evaluate body in new environment */
  return l.body().accept(newEV);
}

