/** Class for a lazy cons structure using call-by-name (redundant) lazy evaluation. */
static class JamLazyNameCons extends JamCons {
  /** Suspension for first */
  protected Suspension firstSusp;
  /** Suspension for rest */
  protected Suspension restSusp;

  public JamLazyNameCons(Suspension first, Suspension rest) {
    super(null, null);
    firstSusp = first;
    restSusp = rest;
  }

  /** Returns the first element by forcing evaluation of the suspension */
  public JamVal first() {
    if (first == null) {
      first = firstSusp.eval();
    }
    return first;
  }

  /** Returns the rest (which must be a list) by forcing evaluation of the suspension */
  public JamList rest() {
    if (rest == null) {
      JamVal restVal = restSusp.eval();
      if (restVal instanceof JamList) {
        rest = restVal;
      } else {
        throw new EvalException("Second argument to lazy cons is `" + restVal + "' which is not a list");
      }
    }
    return (JamList) rest;
  }
}

