/** Class for a lazy cons with call-by-need optimization (caches evaluated values). */
static class JamLazyNeedCons extends JamLazyNameCons {
  /** Flag indicating if first has been evaluated */
  private boolean firstEvaluated = false;
  /** Flag indicating if rest has been evaluated */
  private boolean restEvaluated = false;

  public JamLazyNeedCons(Suspension first, Suspension rest) {
    super(first, rest);
  }

  /** Returns the first element, caching the result */
  @Override
  public JamVal first() {
    if (!firstEvaluated) {
      first = firstSusp.eval();
      firstSusp = null;  // Release for garbage collection
      firstEvaluated = true;
    }
    return first;
  }

  /** Returns the rest, caching the result */
  @Override
  public JamList rest() {
    if (!restEvaluated) {
      JamVal restVal = restSusp.eval();
      if (restVal instanceof JamList) {
        rest = restVal;
      } else {
        throw new EvalException("Second argument to lazy cons is `" + restVal + "' which is not a list");
      }
      restSusp = null;  // Release for garbage collection
      restEvaluated = true;
    }
    return (JamList) rest;
  }
}

